module counter_16bit_up_down(
    input clk, reset, up, down,
    output reg [15:0] count);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            count <= 16'b0;
        else if (up)
            count <= count + 1;
        else if (down)
            count <= count - 1;
    end
endmodule
